<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">        spin_lock</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&amp;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">lock);</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">  /* 试图获取同一把锁...死锁！ */</span></span>
